#!/usr/bin/env node
import { readFileSync, writeFileSync } from "node:fs";
import { resolve } from "node:path";

const root = resolve(import.meta.dirname, "..");
const indexPath = resolve(root, "index.html");
const catalogPath = resolve(root, "catalog.eh.json");
const outputPath = resolve(root, "index.file-dev.html");

const indexHtml = readFileSync(indexPath, "utf8");
const catalog = JSON.parse(readFileSync(catalogPath, "utf8"));

if (!Array.isArray(catalog)) {
  throw new Error("catalog.eh.json must contain a JSON array");
}

const injection = `<script>
// Generated by scripts/build-file-dev.mjs. Do not edit this file by hand.
// This lets index.file-dev.html work from file:// without making index.html a second catalog source.
window.__EH_LOOKUP_DEV_CATALOG__ = ${JSON.stringify(catalog).replaceAll("<", "\\u003c")};
</script>
`;

const marker = "\n<script>\n/* ============================================================\n   ExtraHop Product Catalog";
if (!indexHtml.includes(marker)) {
  throw new Error("Could not find application script marker in index.html");
}

const output = indexHtml.replace(marker, `\n${injection}${marker.trimStart()}`);
writeFileSync(outputPath, output);

console.log(`Wrote ${outputPath}`);
console.log(`Embedded ${catalog.length} catalog entries for local file:// dev use`);
